package jwt

import (
	"crypto/rsa"
	"testing"

	"github.com/cloudflare/circl/sign/mldsa/mldsa87"
	"github.com/stretchr/testify/assert"
)

func TestJWKSKeyLoadPublicKeyRSA(t *testing.T) {
	// From https://datatracker.ietf.org/doc/html/rfc7517#appendix-A.1
	jwksKey := &JWKSKey{
		Kty: "RSA",
		N:   "0vx7agoebGcQSuuPiLJXZptN9nndrQmbXEps2aiAFbWhM78LhWx4cbbfAAtVT86zwu1RK7aPFFxuhDR1L6tSoc_BJECPebWKRXjBZCiFV4n3oknjhMstn64tZ_2W-5JsGY4Hc5n9yBXArwl93lqt7_RN5w6Cf0h4QyQ5v-65YGjQR0_FDW2QvzqY368QQMicAtaSqzs8KJZgnYb9c7d0zgdAZHzu6qMQvRL5hajrn1n91CbOpbISD08qNLyrdkt-bFTWhAI4vMQFh6WeZu0fM4lFd2NcRwr3XPksINHaQ-G_xBniIqbw0Ls1jF44-csFCur-kEgU8awapJzKnqDKgw",
		E:   "AQAB",
		Alg: "RS256",
		Kid: "2011-04-29",
	}

	rsaPubKey, err := jwksKey.LoadPublicKey()
	assert.NoError(t, err)
	assert.NotNil(t, rsaPubKey)
	assert.IsType(t, &rsa.PublicKey{}, rsaPubKey)
}

